class Solution {
    public int leastOpsExpressTarget(int x, int target) {
        if (x == target) return 0;
        if (target == 1) return 1;
        int res = 0, t = target;
        while (t % x == 0) {
            res++;
            t /= x;
        }
        if (t == 1) return res;
        int add = res + 2, mul = res;
        for (int i = 2; i * i <= target; i++) {
            if (target % i == 0) {
                int cnt = 0;
                while (target % i == 0) {
                    target /= i;
                    cnt++;
                }
                add += cnt;
                mul += cnt;
            }
        }
        if (target > 1) {
            add += 2;
            mul += 1;
        }
        return Math.min(add, mul);
    }
}
```
